make_mock_ps_bundle <- function() {
  out <- list(
    spec = list(
      meta = list(
        type = "ps_logit",
        include_intercept = TRUE
      )
    ),
    code = quote({
      beta[1] ~ dnorm(0, 1)
    }),
    data = list(X = cbind(`(Intercept)` = 1, x1 = c(-1, 0, 1, 2))),
    monitors = "beta"
  )
  class(out) <- "causalmixgpd_ps_bundle"
  out
}

