  expect_equal(dim(cqte_out$fit), c(3, 2))
  expect_s3_class(cate_out$fit_df, "data.frame")
  expect_s3_class(cate_rm$fit_df, "data.frame")
  expect_s3_class(cqte_out$fit_df, "data.frame")
  expect_true(is.na(cate_out$nsim_mean))
